{
    "level": "A1–A2",
    "intro": "In this topic you will learn the difference between countable and uncountable nouns - how to distinguish them and use them correctly. count:",
    "rules": [
        {
            "label": "Countable",
            "color": "emerald",
            "text": "<strong>Злічувані</strong> — можна порахувати:",
            "example": "one apple, two apples, three books"
        },
        {
            "label": "Uncountable",
            "color": "amber",
            "text": "<strong>Uncountable</strong> — cannot be counted:",
            "example": "water, information, advice, music"
        },
        {
            "label": "Articles",
            "color": "blue",
            "text": "<strong>Articles:</strong> a/an - only countable:",
            "example": "a book ✓ / a water ✗"
        }
    ]
}

{
    "title": "1. What are countable and uncountable nouns?",
    "intro": "Nouns are divided into two categories:",
    "items": [
        {
            "label": "Countable",
            "title": "Countable",
            "subtitle": "Can be counted, have singular and plural (apple → apples)"
        },
        {
            "label": "Uncountable",
            "title": "Uncountable",
            "subtitle": "Cannot be counted, have no plural (water, music)"
        },
        {
            "label": "Both",
            "title": "Both forms",
            "subtitle": "Some nouns can be both (chicken — chicken / chicken)"
        }
    ]
}

{
    "title": "2. Countable Nouns ",
    "sections": [
        {
            "label": "Countable nouns",
            "color": "emerald",
            "description": "<strong>Countable nouns</strong> can be counted. They have <strong>singular</strong> and <strong>plural</strong>.",
            "examples": [
                {
                    "en": "one book, two books, three books",
                    "ua": "one book, two books, three books"
                },
                {
                    "en": "a cat, some cats, many cats",
                    "ua": "kat, several cats, many cats"
                },
                {
                    "en": "an idea, many ideas pen.",
                    "ua": "ідея, кілька ідей"
                }
            ]
        },
        {
            "label": "З артиклями a/an",
            "color": "sky",
            "description": "Злічувані іменники в однині вживаються з <strong>a/an</strong> або іншим визначником.",
            "examples": [
                {
                    "en": "I need a pen.",
                    "ua": "Мені потрібна ручка."
                },
                {
                    "en": "She is an engineer.",
                    "ua": "She is an engineer."
                },
                {
                    "en": "Give me the book.",
                    "ua": "Give me the book."
                }
            ],
            "note": "❌ It is not possible: <em>I need pen.</em> — without an article is incorrect!"
        },
        {
            "label": "Examples countable",
            "color": "amber",
            "description": "Typical countable nouns:",
            "examples": [
                {
                    "en": "book, pen, table, chair",
                    "ua": "book, pen, table, chair"
                },
                {
                    "en": "apple, banana, egg, sandwich",
                    "ua": "apple, banana, egg, sandwich"
                },
                {
                    "en": "person, friend, student, teacher",
                    "ua": "person, friend, student, teacher"
                },
                {
                    "en": "idea, problem, question, answer",
                    "ua": "idea, problem, question, answer"
                }
            ]
        }
    ]
}

{
    "title": "3. Uncountable Nouns ",
    "sections": [
        {
            "label": "Uncountable Nouns",
            "color": "amber",
            "description": "<strong>Uncountable Nouns</strong> cannot be counted. They <strong>have no plural</strong> and are used with a singular verb.",
            "examples": [
                {
                    "en": "Water is important.",
                    "ua": "Water is important. (not waters)"
                },
                {
                    "en": "Information is useful.",
                    "ua": "Information is useful. (not informations)"
                },
                {
                    "en": "Music makes me happy.",
                    "ua": "Music makes me happy."
                }
            ]
        },
        {
            "label": "No article a/an",
            "color": "rose",
            "description": "Uncountable nouns are <strong>NOT used</strong> with articles a/an.",
            "examples": [
                {
                    "en": "✓ I need water.",
                    "ua": "I need a water."
                },
                {
                    "en": "✗ I need a water.",
                    "ua": "(wrong!)"
                },
                {
                    "en": "✓ She gave me advice.",
                    "ua": "She gave me advice.[[[CODX_13]]]✗ She gave me an advice: juice"
                },
                {
                    "en": "✗ She gave me an advice.",
                    "ua": "(неправильно!)"
                }
            ]
        },
        {
            "label": "Категорії незлічуваних",
            "color": "sky",
            "description": "Основні групи незлічуваних іменників:",
            "examples": [
                {
                    "en": "Liquids: water, milk, coffee, tea, juice",
                    "ua": "Рідини: вода, молоко, кава, чай, сік"
                },
                {
                    "en": "Materials: wood, plastic, glass, paper",
                    "ua": "Materials: wood, plastic, glass, paper"
                },
                {
                    "en": "Abstract: information, advice, news, knowledge",
                    "ua": "Abstract: information, advice, news, knowledge"
                },
                {
                    "en": "Food masses: rice, bread, sugar, salt, meat",
                    "ua": "Food (mass): rice, bread, sugar, salt, meat"
                }
            ]
        }
    ]
}

{
    "title": "4. How to measure uncountable nouns",
    "sections": [
        {
            "label": "Units of measurement",
            "color": "emerald",
            "description": "To "count" uncountables, we use <strong>units of measurement</strong>.",
            "examples": [
                {
                    "en": "a glass of water",
                    "ua": "a glass of water"
                },
                {
                    "en": "a cup of coffee",
                    "ua": "a cup of coffee"
                },
                {
                    "en": "a bottle of milk",
                    "ua": "a bottle of milk"
                },
                {
                    "en": "a piece of advice",
                    "ua": "advice (one)"
                }
            ]
        },
        {
            "label": "Typical designs",
            "color": "sky",
            "description": "Popular methods of measurement:",
            "examples": [
                {
                    "en": "a piece of: cake, paper, news, furniture[[[CODX_5]]]piece/part: cake, paper, news, furniture",
                    "ua": "шматок/частина: торта, паперу, новина, меблі"
                },
                {
                    "en": "a slice of: bread, pizza, cheese",
                    "ua": "a slice of: bread, pizza, cheese"
                },
                {
                    "en": "a loaf of: bread",
                    "ua": "a loaf of bread"
                },
                {
                    "en": "a bar of: chocolate, soap",
                    "ua": "a bar of: chocolate, a piece dear"
                }
            ]
        },
        {
            "label": "Some / A bit of",
            "color": "amber",
            "description": "For an unspecified amount:",
            "examples": [
                {
                    "en": "some water, some information",
                    "ua": "a bit of luck, a bit of help"
                },
                {
                    "en": "a bit of luck, a bit of help",
                    "ua": "a bit of luck, a bit of help of help"
                },
                {
                    "en": "a little sugar, a little time",
                    "ua": "a little sugar, a little time"
                }
            ]
        }
    ]
}

{
    "title": "5. Quantifiers",
    "sections": [
        {
            "label": "Only countables",
            "color": "emerald",
            "description": "These words are used <strong>only with countables</strong>:",
            "examples": [
                {
                    "en": "many books, many friends",
                    "ua": "many books, many friends"
                },
                {
                    "en": "a few questions",
                    "ua": "several ideas"
                },
                {
                    "en": "few people (few - negative)",
                    "ua": "few people"
                },
                {
                    "en": "several ideas",
                    "ua": "several ideas"
                }
            ]
        },
        {
            "label": "Only countless",
            "color": "amber",
            "description": "These words are used <strong>only with uncountables</strong>:",
            "examples": [
                {
                    "en": "much time, much money",
                    "ua": "much time, much money"
                },
                {
                    "en": "a little water",
                    "ua": "little water"
                },
                {
                    "en": "little hope (little - negative)",
                    "ua": "little hope"
                }
            ]
        },
        {
            "label": "Both types",
            "color": "sky",
            "description": "Universal words for <strong>both types</strong>:",
            "examples": [
                {
                    "en": "some books / some water",
                    "ua": "a lot of friends / a lot of time"
                },
                {
                    "en": "any questions / any information",
                    "ua": "будь-які питання / будь-яка інформація"
                },
                {
                    "en": "a lot of friends / a lot of time",
                    "ua": "a lot of friends / a lot of time"
                },
                {
                    "en": "lots of people / lots of money",
                    "ua": "many people / a lot of money"
                }
            ]
        }
    ]
}

{
    "title": "6. Comparison table",
    "intro": "Main differences between countable and uncountable:",
    "rows": [
        {
            "en": "Plural form",
            "ua": "Plurality",
            "note": "Countable: books ✓ / Uncountable: waters ✗"
        },
        {
            "en": "A / An",
            "ua": "Article a/an",
            "note": "Countable: a book ✓ / Uncountable: a water ✗"
        },
        {
            "en": "Numbers",
            "ua": "Numbers",
            "note": "Countable: two books ✓ / Uncountable: two waters ✗"
        },
        {
            "en": "Many / A lot Any</strong> - universal for both types!",
            "ua": "Багато",
            "note": "Countable: many ✓ / Uncountable: much ✓"
        },
        {
            "en": "Few / Little",
            "ua": "Мало",
            "note": "Countable: few ✓ / Uncountable: little ✓"
        }
    ],
    "warning": "📌 <strong>A lot of / Some / Any</strong> — універсальні для обох типів!"
}

{
    "title": "7. Nouns with double meaning",
    "sections": [
        {
            "label": "Uncountable",
            "color": "purple",
            "description": "Some nouns can be <strong>countable OR uncountable</strong> with different meaning:",
            "examples": [
                {
                    "en": "chicken (uncountable) = meat",
                    "ua": "chicken (meat)[[[CODX_1]]]a chicken (countable) = bird cup"
                },
                {
                    "en": "a chicken (countable) = bird",
                    "ua": "курка (птах)"
                },
                {
                    "en": "coffee (uncountable) = drink",
                    "ua": "кава (напій)"
                },
                {
                    "en": "a coffee (countable) = a cup",
                    "ua": "cup of coffee"
                }
            ]
        },
        {
            "label": "More examples",
            "color": "sky",
            "description": "Other nouns with double meaning:",
            "examples": [
                {
                    "en": "glass (uncountable) = material",
                    "ua": "glass (material)"
                },
                {
                    "en": "a glass (countable) = container",
                    "ua": "glass (dishes)"
                },
                {
                    "en": "paper (uncountable) = material",
                    "ua": "paper (material)"
                },
                {
                    "en": "a paper (countable) = document/newspaper",
                    "ua": "document / newspaper"
                }
            ]
        }
    ]
}

{
    "title": "8. Typical mistakes of Ukrainian speakers",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "The set of uncountables.",
            "wrong": "I need some information.",
            "right": "​​​​ <span class="font-mono">I need some information.</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Article a/an with uncountables.",
            "wrong": "Can I have a water?",
            "right": "​​​​​​​​ countable."
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Much зі злічуваними.",
            "wrong": "There are many books here.",
            "right": " ✅ <span class="font-mono">There are many books here.</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Many with uncountable.",
            "wrong": "I have many money.",
            "right": "​​​​ <span class="font-mono">I have a lot of money. / I have a lot of money.</span>"
        }
    ]
}

{
    "title": "10. Practice",
    "select_title": "Exercise 1. Determine the type of noun",
    "select_intro": "Determine whether the noun is countable (C) or uncountable (U).",
    "selects": [
        {
            "label": "water (C / U)",
            "prompt": "What type? "
        },
        {
            "label": "book (C / U)",
            "prompt": "What type?"
        },
        {
            "label": "information (C / U)",
            "prompt": "What type?"
        },
        {
            "label": "apple (C / U)",
            "prompt": "What type?"
        }
    ],
    "options": [
        "Countable",
        "Uncountable"
    ],
    "input_title": "Exercise 2. Choose many or much",
    "input_intro": "Fill in the blanks with many or much.",
    "inputs": [
        {
            "before": "How ___ books do you have?",
            "after": "→"
        },
        {
            "before": "I don't have ___ time.",
            "after": "→"
        },
        {
            "before": "There are ___ people here.",
            "after": "→"
        }
    ],
    "rephrase_title": "Exercise 3. Correcting mistakes",
    "rephrase_intro": "Find and correct an error in the sentence.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "I need an advice.",
            "example_target": "I need some advice. / I need a piece of advice."
        },
        {
            "original": "1. She gave me many informations.",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. Can I have a dairy? Quantity",
            "placeholder": "Виправ помилку"
        }
    ]
}

{
    "title": "Інші сторінки з категорії Іменники, артиклі та кількість",
    "items": [
        {
            "label": "Countable vs Uncountable — Злічувані / незлічувані (поточна)",
            "current": true
        },
        {
            "label": "Articles — Артиклі a/an/the",
            "current": false
        },
        {
            "label": "Some / Any — Кількість",
            "current": false
        },
        {
            "label": "Much / Many / A lot of",
            "current": false
        }
    ]
}
